import React, { useState, useEffect } from "react";
import axios from "axios";

export default function ShowEmployee() {
  const [employees, setEmployees] = useState([]);

  useEffect(() => {
    // Fetch all employees when component mounts
    axios
      .get("http://localhost:8080/findallemp")
      .then((response) => {
        setEmployees(response.data);
      })
      .catch((error) => {
        console.error(error);
        alert("Error in fetching data ❌");
      });
  }, []); // empty dependency array → runs only once on mount

  return (
    <div style={{ textAlign: "center", marginTop: "50px" }}>
      <h2>All Employees</h2>

      {employees.length === 0 ? (
        <p>No employees found.</p>
      ) : (
        <table
          style={{
            margin: "auto",
            borderCollapse: "collapse",
            width: "80%",
          }}
        >
          <thead>
            <tr>
              <th style={{ border: "1px solid black", padding: "8px" }}>Emp ID</th>
              <th style={{ border: "1px solid black", padding: "8px" }}>Name</th>
              <th style={{ border: "1px solid black", padding: "8px" }}>Email</th>
              <th style={{ border: "1px solid black", padding: "8px" }}>Contact</th>
              <th style={{ border: "1px solid black", padding: "8px" }}>Department</th>
            </tr>
          </thead>
          <tbody>
            {employees.map((emp) => (
              <tr key={emp.empid}>
                <td style={{ border: "1px solid black", padding: "8px" }}>{emp.empid}</td>
                <td style={{ border: "1px solid black", padding: "8px" }}>
                  {emp.firstName} {emp.lastName}
                </td>
                <td style={{ border: "1px solid black", padding: "8px" }}>{emp.email}</td>
                <td style={{ border: "1px solid black", padding: "8px" }}>{emp.contactNo}</td>
                <td style={{ border: "1px solid black", padding: "8px" }}>{emp.department}</td>
              </tr>
            ))}
          </tbody>
        </table>
      )}
    </div>
  );
}
